function loadData(){
  const raw=localStorage.getItem("tydenniPlanData");
  if(!raw){ alert("Nic není uložené."); return; }
  const data=JSON.parse(raw);
  document.getElementById("weekFrom").value=data.weekFrom||"";
  document.getElementById("weekTo").value=data.weekTo||"";
  document.getElementById("signature").value=data.signature||"";
  events=data.events||[];
  longEvents=data.longEvents||[];
  renderAll();
}
function clearAll(){
  if(!confirm("Opravdu smazat celý plán?")) return;
  events=[]; longEvents=[];
  document.querySelectorAll("input,textarea").forEach(el=>{ if(el.id!=="signature" && el.type !== "file") el.value=""; });
  setDefaultWeek();
  renderAll();
}

function setWeekByDate(baseDate){
  const day = baseDate.getDay() || 7;
  const monday = new Date(baseDate);
  monday.setDate(baseDate.getDate() - day + 1);
  const sunday = new Date(monday);
  sunday.setDate(monday.getDate() + 6);
  document.getElementById("weekFrom").value = dateToInput(monday);
  document.getElementById("weekTo").value = dateToInput(sunday);
  document.getElementById("eventDate").value = dateToInput(monday);
}

function setDefaultWeek(){
  setWeekByDate(new Date());
}

function setCurrentWeekAndImport(){
  setWeekByDate(new Date());
  importWeekFromCalendar();
}

function moveWeek(days){
  const current = parseDate(document.getElementById("weekFrom").value) || new Date();
  current.setDate(current.getDate() + days);
  setWeekByDate(current);
  importWeekFromCalendar();
}

function setNearestWeekWithEvents(){
  if(!calendarEvents.length){
    alert("Nejdřív načti kalendář.");
    return;
  }

  const today = new Date();
  const todayKey = dateToInput(today);

  const future = calendarEvents
    .filter(e => e.startDate >= todayKey)
    .sort((a,b) => a.startDate.localeCompare(b.startDate));

  const chosen = future[0] || calendarEvents.sort((a,b) => a.startDate.localeCompare(b.startDate))[0];

  setWeekByDate(parseDate(chosen.startDate));
  importWeekFromCalendar();
}

async function loadCalendarFromUrl(){
  try{
    const info = document.getElementById("calendarInfo");
    if(info) info.textContent = "Načítám živý kalendář z EduPage…";

    const res = await fetch("/calendar.ics?t=" + Date.now(), { cache: "no-store" });
    const text = await res.text();

    if(!res.ok){
      throw new Error("Kalendář se nepodařilo načíst. HTTP " + res.status);
    }

    if(!text.includes("BEGIN:VCALENDAR")){
      throw new Error("Načtená odpověď nevypadá jako kalendář. Pravděpodobně se nepoužil Netlify redirect.");
    }

    calendarEvents = parseIcs(text);
    setCalendarInfo();
    setNearestWeekWithEvents();
  }catch(err){
    console.error(err);
    setCalendarInfo();
    alert("Živý kalendář se nepodařilo načíst. Detail: " + err.message);
  }
}

setDefaultWeek();
setCalendarInfo();
renderAll();
loadCalendarFromUrl();

